import hmac
import hashlib
import base64
import time
import struct
import io
import secrets
import qrcode
from urllib.parse import quote


class TOTPAuthenticator:
    def __init__(self, issuer_name="MyApp", digits=6, period=30, algorithm='sha1'):
        self.issuer_name = issuer_name
        self.digits = digits
        self.period = period
        self.algorithm = algorithm
        
    def generate_secret(self, length=32):
        random_bytes = secrets.token_bytes(length)
        secret = base64.b32encode(random_bytes).decode('utf-8')
        return secret.rstrip('=')
    
    def get_hotp_token(self, secret, counter):
        key = base64.b32decode(secret + '=' * ((8 - len(secret)) % 8))
        
        counter_bytes = struct.pack('>Q', counter)
        
        if self.algorithm == 'sha1':
            hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
        elif self.algorithm == 'sha256':
            hmac_hash = hmac.new(key, counter_bytes, hashlib.sha256).digest()
        elif self.algorithm == 'sha512':
            hmac_hash = hmac.new(key, counter_bytes, hashlib.sha512).digest()
        else:
            raise ValueError(f"Unsupported algorithm: {self.algorithm}")
        
        offset = hmac_hash[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_hash[offset:offset+4])[0] & 0x7FFFFFFF
        
        token = truncated % (10 ** self.digits)
        return str(token).zfill(self.digits)
    
    def get_totp_token(self, secret, timestamp=None):
        if timestamp is None:
            timestamp = time.time()
        
        counter = int(timestamp // self.period)
        return self.get_hotp_token(secret, counter)
    
    def verify_totp(self, secret, token, timestamp=None, window=1):
        if timestamp is None:
            timestamp = time.time()
        
        current_counter = int(timestamp // self.period)
        
        for offset in range(-window, window + 1):
            counter = current_counter + offset
            expected_token = self.get_hotp_token(secret, counter)
            
            if hmac.compare_digest(expected_token, token):
                return True
        
        return False
    
    def get_provisioning_uri(self, secret, account_name, issuer=None):
        if issuer is None:
            issuer = self.issuer_name
        
        label = f"{issuer}:{account_name}" if issuer else account_name
        
        params = {
            'secret': secret,
            'issuer': issuer,
            'algorithm': self.algorithm.upper(),
            'digits': self.digits,
            'period': self.period
        }
        
        param_string = '&'.join([f"{k}={quote(str(v))}" for k, v in params.items()])
        uri = f"otpauth://totp/{quote(label)}?{param_string}"
        
        return uri
    
    def generate_qr_code(self, secret, account_name, issuer=None):
        uri = self.get_provisioning_uri(secret, account_name, issuer)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        return img
    
    def save_qr_code(self, secret, account_name, filename, issuer=None):
        img = self.generate_qr_code(secret, account_name, issuer)
        img.save(filename)
        
    def get_qr_code_bytes(self, secret, account_name, issuer=None):
        img = self.generate_qr_code(secret, account_name, issuer)
        buffer = io.BytesIO()
        img.save(buffer, format='PNG')
        buffer.seek(0)
        return buffer.getvalue()
    
    def get_current_counter(self, timestamp=None):
        if timestamp is None:
            timestamp = time.time()
        return int(timestamp // self.period)
    
    def get_time_remaining(self, timestamp=None):
        if timestamp is None:
            timestamp = time.time()
        return self.period - (int(timestamp) % self.period)


class UserTOTPManager:
    def __init__(self, issuer_name="MyApp"):
        self.authenticator = TOTPAuthenticator(issuer_name=issuer_name)
        self.user_secrets = {}
        
    def register_user(self, user_id, username):
        secret = self.authenticator.generate_secret()
        self.user_secrets[user_id] = {
            'secret': secret,
            'username': username,
            'created_at': time.time()
        }
        return secret
    
    def get_user_secret(self, user_id):
        if user_id in self.user_secrets:
            return self.user_secrets[user_id]['secret']
        return None
    
    def generate_user_qr_code(self, user_id):
        if user_id not in self.user_secrets:
            raise ValueError(f"User {user_id} not registered")
        
        secret = self.user_secrets[user_id]['secret']
        username = self.user_secrets[user_id]['username']
        
        return self.authenticator.generate_qr_code(secret, username)
    
    def save_user_qr_code(self, user_id, filename):
        if user_id not in self.user_secrets:
            raise ValueError(f"User {user_id} not registered")
        
        secret = self.user_secrets[user_id]['secret']
        username = self.user_secrets[user_id]['username']
        
        self.authenticator.save_qr_code(secret, username, filename)
    
    def get_user_qr_code_bytes(self, user_id):
        if user_id not in self.user_secrets:
            raise ValueError(f"User {user_id} not registered")
        
        secret = self.user_secrets[user_id]['secret']
        username = self.user_secrets[user_id]['username']
        
        return self.authenticator.get_qr_code_bytes(secret, username)
    
    def verify_user_token(self, user_id, token, window=1):
        if user_id not in self.user_secrets:
            return False
        
        secret = self.user_secrets[user_id]['secret']
        return self.authenticator.verify_totp(secret, token, window=window)
    
    def get_user_provisioning_uri(self, user_id):
        if user_id not in self.user_secrets:
            raise ValueError(f"User {user_id} not registered")
        
        secret = self.user_secrets[user_id]['secret']
        username = self.user_secrets[user_id]['username']
        
        return self.authenticator.get_provisioning_uri(secret, username)
    
    def remove_user(self, user_id):
        if user_id in self.user_secrets:
            del self.user_secrets[user_id]
            return True
        return False


